// Topic format:
// <room>/<type>/<field> (where <type> is data or control)

var parts = msg.topic.split("/");
if (parts.length !== 3) {
    return null;
}

var room = parts[0];
var type = parts[1];
var field = parts[2];

if (type !== "data" && type !== "control") {
    node.warn("Unknown type: " + type);
    return null;
}

// Set measurement name dynamically based on type (data or control)
msg.measurement = "classroom_" + type;

// Build field name from topic
var influxField = type + "_" + field;

const stringFields = ["ac", "status", "command"];
const intFields = [
    "active",
    "alert",
    "co2",
    "human",
    "led",
    "lux",
    "projector",
    "led_data",
    "ac_data",
    "projector_data"
];
const floatFields = ["temp"];

var value;

if (intFields.includes(field)) {
    value = parseInt(msg.payload, 10);

    if (isNaN(value)) return null;

    // VERY IMPORTANT
    value = value.toString() + "i";
}
else if (floatFields.includes(field)) {
    value = parseFloat(msg.payload);

    if (isNaN(value)) return null;
}
else if (stringFields.includes(field)) {
    // If it's status or command, check if it can be parsed as an integer first
    if (field === "status" || field === "command") {
        let parsed = parseInt(msg.payload, 10);
        if (!isNaN(parsed) && String(parsed) === String(msg.payload).trim()) {
            value = parsed.toString() + "i";
        } else {
            value = String(msg.payload);
        }
    } else {
        value = String(msg.payload);
    }
}
else {
    node.warn("Unknown field: " + field);
    return null;
}

msg.payload = [
    {
        [field]: value
    },
    {
        room: room
    }
];

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/" +
    row._field;

msg.payload = String(row._value);

return msg;

let row = msg.payload;

msg.topic =

    row.room +
    "/control/schedule";

msg.payload = String(row._value);

return msg;

const days = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday"
];

msg.payload = days[new Date().getDay()];
return msg;

// Extract the raw status text from the node
let mqttState = msg.status.text;

// Map the text to integers
if (mqttState === "node-red:common.status.connected") {
    msg.payload = 2; 
} else if (mqttState === "node-red:common.status.connecting") {
    msg.payload = 1;
} else {
    // This catches "disconnected", "error", or any other failure state
    msg.payload = 0; 
}

return msg;

let rooms = {};
let now = Date.now();

if (!Array.isArray(msg.payload)) {
    return null;
}

msg.payload.forEach(row => {
    let room = row.room;
    if (!room) return;

    if (!rooms[room]) {
        rooms[room] = {
            room: room,
            lastSeen: 0,
            temp: "-",
            lux: "-",
            co2: "-",
            led_data: 0,
            ac_data: 0,
            projector_data: 0,
            status: 0,
            ac_temp: 24
        };
    }

    let field = row._field;
    let val = row._value;
    let time = new Date(row._time).getTime();

    if (time > rooms[room].lastSeen) {
        rooms[room].lastSeen = time;
    }

    if (field === "temp" || field === "temperature") {
        rooms[room].temp = parseFloat(val).toFixed(1);
    } else if (field === "lux") {
        rooms[room].lux = val;
    } else if (field === "co2") {
        rooms[room].co2 = val;
    } else if (field === "led_data") {
        rooms[room].led_data = parseInt(val, 10);
    } else if (field === "ac_data") {
        rooms[room].ac_data = parseInt(val, 10);
    } else if (field === "projector_data") {
        rooms[room].projector_data = parseInt(val, 10);
    } else if (field === "active") {
        rooms[room].active = parseInt(val, 10);
    } else if (field === "ac_temp") {
        rooms[room].ac_temp = parseInt(val, 10);
    }
});

Object.keys(rooms).forEach(roomName => {
    let r = rooms[roomName];
    let elapsed = now - r.lastSeen;

    if (elapsed > 300000) {
        r.temp = "-";
        r.lux = "-";
        r.co2 = "-";
        r.status = -1;
        r.led_data = -1;
        r.ac_data = -1;
        r.projector_data = -1;
    } else {
        r.status = r.active === 1 ? 1 : 0;
    }
});

let msgRooms = {
    topic: "rooms",
    payload: Object.values(rooms)
};
let msgLed = {
    payload: 1
};
return [msgRooms, msgLed];

if (msg.topic === "control") {
    let payload = msg.payload;
    let room = payload.room;
    let device = payload.device;
    let value = payload.value;

    let msgMqtt = {
        topic: room + "/control/" + device,
        payload: String(value)
    };

    let msgInflux = {
        measurement: "classroom_control",
        payload: [
            { [device]: value },
            { room: room }
        ]
    };

    return [msgMqtt, msgInflux, null];
} 
else if (msg.topic === "get_history") {
    let room = msg.payload.room;
    let range = msg.payload.range || "24h";

    let rangePart = '';
    if (range === 'custom') {
        let start = msg.payload.start ? new Date(msg.payload.start).toISOString() : new Date(Date.now() - 24*3600*1000).toISOString();
        let stop = msg.payload.stop ? new Date(msg.payload.stop).toISOString() : new Date().toISOString();
        rangePart = `|> range(start: ${start}, stop: ${stop})`;
    } else {
        rangePart = `|> range(start: -${range})`;
    }

    let msgQuery = {
        payload: room,
        query: `from(bucket: "SmartClass")
  ${rangePart}
  |> filter(fn: (r) => r.room == "${room}")
  |> filter(fn: (r) => r._measurement == "classroom")
  |> filter(fn: (r) => r._field == "temp" or r._field == "lux" or r._field == "co2")`
    };

    return [null, null, msgQuery];
}

return null;

if (!Array.isArray(msg.payload)) {
    return null;
}

let records = msg.payload;
let room = records.length > 0 ? records[0].room : "";

let historyData = {
    temp: [],
    lux: [],
    co2: []
};

records.forEach(row => {
    let field = row._field;
    let value = parseFloat(row._value);
    let time = new Date(row._time).getTime();

    if (field === "temp" || field === "temperature") {
        historyData.temp.push({ x: time, y: value });
    } else if (field === "lux") {
        historyData.lux.push({ x: time, y: value });
    } else if (field === "co2") {
        historyData.co2.push({ x: time, y: value });
    }
});

historyData.temp.sort((a, b) => a.x - b.x);
historyData.lux.sort((a, b) => a.x - b.x);
historyData.co2.sort((a, b) => a.x - b.x);

msg.topic = "history";
msg.room = room;
msg.payload = historyData;

return msg;
